public void testFoldGetElemMultipleHoles() {
  fold("x = [,,,30][3]", "x = 30");
  fold("x = [,20,,40][1]", "x = 20");
  fold("x = [,,,][0]", "x = void 0");
  fold("x = [10,,,40][2]", "x = void 0");
}

public void testFoldGetElemBoundaryConditions() {
  fold("x = [100][0]", "x = 100");
  fold("x = [5,15,25,35,45][4]", "x = 45");
  fold("x = [1,2,3,4,5][5]", "",
      PeepholeFoldConstants.INDEX_OUT_OF_BOUNDS_ERROR);
}
